	let select_knjiga = document.querySelector("#pretraga_biblije_div > div:nth-child(1) > select"),
		select_poglavlje = document.querySelector("#pretraga_biblije_div > div:nth-child(2) > select"),
		select_redak = document.querySelector("#pretraga_biblije_div > div:nth-child(3) > select");
	let pretrazi_gumb = document.querySelector("#pretraga_biblije_div > div:nth-child(4) > button");
	let sadrzaj_biblije_div = document.querySelector("#sadrzaj_biblije_div");
	var rb_odabrana_knjiga;
	var odabrana_knjiga;
	var odabrano_poglavlje;
	var odabran_redak;

	/*select_knjiga.onchange = select_poglavlje.onchange = select_redak.onchange = function() {
		if (this.selectedIndex && this.selectedIndex > 0)
		{

		}
	};*/
	for (knjiga in Bib_len)
	{
		let opt = document.createElement("option");
		opt.innerText = knjiga;
		select_knjiga.insertAdjacentElement('beforeend', opt);
	}
	select_knjiga.onchange = function() {
		odabrana_knjiga = null;
		let opcije_poglavlje = select_poglavlje.querySelectorAll("option");
		for (let i = opcije_poglavlje.length - 1; i > 0; --i)
			opcije_poglavlje[i].remove();
		let opcije_redak = select_redak.querySelectorAll("option");
		for (let i = opcije_redak.length - 1; i > 0; --i)
			opcije_redak[i].remove();

		if (this.selectedIndex && this.selectedIndex > 0)
		{
			odabrana_knjiga = this.options[this.selectedIndex].text;
			rb_odabrana_knjiga = this.selectedIndex;

			let knjiga_len = Bib_len[odabrana_knjiga].length;
			for (let i = 1; i < knjiga_len; ++i)
			{
				let opt = document.createElement("option");
				opt.innerText = i;
				select_poglavlje.insertAdjacentElement("beforeend", opt);
			}
		}
	}
	select_poglavlje.onchange = function() {
		odabrano_poglavlje = null;
		let opcije_redak = select_redak.querySelectorAll("option");
		for (let i = opcije_redak.length - 1; i > 0; --i)
			opcije_redak[i].remove();
		if (this.selectedIndex && this.selectedIndex > 0)
		{
			if (!odabrana_knjiga)
			{
				alert("Prvo odaberite knjigu!");
			}
			else
			{
				odabrano_poglavlje = this.selectedIndex;
				let poglavlje_len = Bib_len[odabrana_knjiga][this.selectedIndex].length;
				for (let i = 1; i < poglavlje_len; ++i)
				{
					let opt = document.createElement("option");
					opt.innerText = i;
					select_redak.insertAdjacentElement("beforeend", opt);
				}
			}
		}
	}
	select_redak.onchange = function() {
		if (this.selectedIndex && this.selectedIndex > 0)
		{
			if (!odabrana_knjiga || !odabrano_poglavlje)
			{
				alert("Prvo odaberite knjigu i poglavlje!");
			}
			else
			{
				odabran_redak = this.selectedIndex;
			}
		}
		else odabran_redak = null;
	}
	pretrazi_gumb.onclick = function() {
		if (!odabrana_knjiga)
		{
			alert("Prvo odaberite knjigu.");
			return;
		}
		// Očisti prethodni sadržaj
		sadrzaj_biblije_div.style.minHeight = "500px";
		sadrzaj_biblije_div.innerHTML = "";
		dohvati_tekst_Biblije(rb_odabrana_knjiga, odabrano_poglavlje, odabran_redak, function () {
			sadrzaj_biblije_div.style.minHeight = "";
		});
	}

	async function dohvati_tekst_Biblije(knjiga, poglavlje, redak, onExit)
	{
		// Knjiga: https://raw.githubusercontent.com/shtef21/shtef21/master/assets/bib/_1
		// Poglavlje: https://raw.githubusercontent.com/shtef21/shtef21/master/assets/bib/1/_1
		// Redak: https://raw.githubusercontent.com/shtef21/shtef21/master/assets/bib/1/1/1
		let url = "https://raw.githubusercontent.com/shtef21/shtef21/master/assets/bib/";

		if (redak)
		{
			await fetch(url + knjiga + "/" + poglavlje + "/" + redak).then(res => res.text()).then(txt => {
				ubaci_vnutri_naslov(odabrana_knjiga, odabrano_poglavlje, odabran_redak);
				ubaci_vnutri_tekst(odabran_redak, txt);
			});
		}
		else if (poglavlje)
		{
			await fetch(url + knjiga + "/_" + poglavlje).then(res => res.text()).then(txt => {
				let linije = txt.split("\n");
				ubaci_vnutri_naslov(odabrana_knjiga, odabrano_poglavlje);
				for (let i = 0; i < linije.length; ++i)
				{
					ubaci_vnutri_tekst(i + 1, linije[i]);
				}
			});
		}
		else if (knjiga)
		{
			await fetch(url + "_" + knjiga).then(res => res.text()).then(txt => {
				let sve_linije = txt.split("\n");
				let rb_knjige = 1;
				let rb_retka = 1;
				ubaci_vnutri_naslov(odabrana_knjiga, rb_knjige);
				for (let i = 0; i < sve_linije.length - 2; ++i)
				{
					if (sve_linije[i] == "" && sve_linije[i + 1] == "")
					{
						++rb_knjige;
						rb_retka = 1;
						i += 2;
						if (i < sve_linije.length - 2) ubaci_vnutri_naslov(odabrana_knjiga, rb_knjige);
					}
					else
					{
						ubaci_vnutri_tekst(rb_retka, sve_linije[i]);
						++rb_retka;
					}
				}
			});
		}

		if (onExit && typeof onExit === "function")
			onExit();
	}
	function ubaci_vnutri_naslov(naziv_knjige, poglavlje, redak)
	{
		let bib_h3 = document.createElement("h3");
		bib_h3.innerText = naziv_knjige + " " + poglavlje;
		if (redak)
			bib_h3.innerText = bib_h3.innerText + ", " + odabran_redak;
		sadrzaj_biblije_div.insertAdjacentElement("beforeend", bib_h3);
	}
	function ubaci_vnutri_tekst(redak_rb, redak_tekst)
	{
		let bib_p = document.createElement("p");
		let bib_sup = document.createElement("sup");
		bib_sup.innerText = "" + redak_rb;
		bib_p.innerText = redak_tekst;
		bib_p.insertAdjacentElement("afterbegin", bib_sup);
		sadrzaj_biblije_div.insertAdjacentElement("beforeend", bib_p);
	}
